    public partial class TemplateEarningService : BaseService<TemplateEarning>, ITemplateEarningService
    {
        public TemplateEarningService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task<TemplateEarning> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<TemplateEarning>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Component).Include(x => x.PercentOnComp),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<TemplateEarning>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<TemplateEarning>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Component.Name.Contains(search.Name)
                     || x.PercentOnComp.Name.Contains(search.Name))
                     && x.TemplateId == search.RefId.Value,
                include: i => i.Include(x => x.Component).Include(x => x.PercentOnComp),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Component.Name", ascending: !search.IsDescend);
        }
    }
